="Aside (Sidebar)" type="length" default="300px" min="250px" max="500px" value="300px" hideEditor="true"/> <Variable name="startSide" description="Side where text starts in blog language" type="automatic" default="left"/> <Variable name="endSide" description="Side where text ends in blog language" type="automatic" default="right"/>
