<Group description="Light Mode"> <Variable name="primary" description="Main Color" type="color" default="#00857c" value="#00857c"/> <Variable name="body.tx.color" description="Body Text Color" type="color" default="#272733" value="#272733"/> <Variable name="body.background.color" description="Body Background Color" type="color" default="#f3f4f6" value="#f3f4f6"/> <Variable name="post.background.color" description="Posts Background Color" type="color" default="#fdfdfd" value="#fdfdfd"/> </Group>
<Group description="Dark Mode"> <Variable name="body.tx.color.dark" description="Body Text Color Dark" type="color" default="#efefef" value="#efefef"/> <Variable name="body.background.color.dark" description="Body Background Color Dark" type="color" default="#161b22" value="#161b22"/> <Variable name="post.background.color.dark" description="Posts Background Color Dark" type="color" default="#1b212a" value="#1b212a"/> </Group>
