<Group description="Single Post Light"> <Variable name="posts.text.color" description="Post Text Color" type="color" default="#536471" value="#536471"/> <Variable name="posts.link.color" description="Post Link Color" type="color" default="$(primary)" value="$(primary)"/> </Group>
