/* LOADING and RIPPLE */ .load, .ripple { top: 0; bottom: 0; $startSide: 0; $endSide: 0; } .load { cursor: progress; } .ripple { height: 60px; width: 60px; } .ripple div { border: 2px solid var(--primary); -moz-animation: ignielRipple 1s cubic-bezier(0, 0.2, 0.8, 1) infinite; -o-animation: ignielRipple 1s cubic-bezier(0, 0.2, 0.8, 1) infinite; -webkit-animation: ignielRipple 1s cubic-bezier(0, 0.2, 0.8, 1) infinite; animation: ignielRipple 1s cubic-bezier(0, 0.2, 0.8, 1) infinite; } .ripple div:nth-child(2) { -moz-animation-delay: -0.5s; -o-animation-delay: -0.5s; -webkit-animation-delay: -0.5s; animation-delay: -0.5s; } .lazy { opacity: 0; transition: opacity .1s; } img.lazyloading { background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent), var(--primary); background-size: 200% 100%; animation: loadingPulse 1.5s infinite linear; border-radius: inherit; opacity: 0.5 !important; } @keyframes loadingPulse { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } } .lazyloaded, .slider .widget-content.lazyloaded { opacity: 1; } .fade { animation: ignielFade .1s ease-out; -moz-animation: ignielFade .1s ease-out; -webkit-animation: ignielFade .1s ease-out; -o-animation: ignielFade .1s ease-out; transition: opacity .1s linear; }
/* SKELETON LOADING */ .skeleton { cursor: progress; -webkit-user-select: none; -moz-user-select: none; -ms-user-select: none; user-select: none; width: 100%; } .skl-top, .skl-bottom, .skl-grid, .skl-slide { animation: skeleton 1s ease-in-out forwards infinite alternate; -webkit-animation: skeleton 1s ease-in-out forwards infinite alternate; transform-origin: top center; } .skl-top { height: 125px; } .skl-bottom { animation-delay: 200ms; height: 10px; margin-top: .5rem; } .skl-bottom.two { width: 75%; } .related-middle-inner .skl-bottom, .offer-inner .skl-bottom { margin-bottom: .75rem; width: 100%; } .related-middle-inner .right, .offer-inner .right { flex-basis: 100%; width: 100%; } .skl-grid { min-height: 185px; } .skl-slide { min-height: 340px; }
/* TABLE */ table thead, table td { background-color: rgba(10, 10, 10, .035); } [data-theme="dark"] table thead, [data-theme="dark"] table td { background-color: rgba(38, 43, 51, .22); } table th, table tr td { border-$endSide: 1px solid rgba(35, 45, 65, .15); } [data-theme="dark"] table, [data-theme="dark"] table th, [data-theme="dark"] table tr td { border-color: rgba(125,145,225,.075); } table th:last-child, table tr td:last-child { border-$endSide: 0; } table th { padding: 1rem .75rem; } table tr td { text-align: $startSide; vertical-align: top; } table tr td, .caption { padding: .65rem 1rem; }
