/* BOX */ .box { padding: .65em .9em; margin: 1.25em 0; } .box.green, .box.blue, .box.red, .box.yellow { padding-$startSide: 2.5em; } .box :is(ol, ul) { padding-inline-start: 1.15em; } .box.green:before, .box.blue:before, .box.red:before, .box.yellow:before { content: ''; background-position: center center; background-repeat: no-repeat; background-size: 1.25em; $startSide: 1em; height: 1em; top: 1em; width: 1em; } .box.green:before { background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M17 3.34a10 10 0 1 1 -14.995 8.984l-.005 -.324l.005 -.324a10 10 0 0 1 14.995 -8.336zm-1.293 5.953a1 1 0 0 0 -1.32 -.083l-.094 .083l-3.293 3.292l-1.293 -1.292l-.094 -.083a1 1 0 0 0 -1.403 1.403l.083 .094l2 2l.094 .083a1 1 0 0 0 1.226 0l.094 -.083l4 -4l.083 -.094a1 1 0 0 0 -.083 -1.32z' fill='%232c9217'/%3E%3C/svg%3E"); } .box.green { background-color: #d4efee; color: #005955; } .box.blue:before { background-color: #1f62cf; background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M12 12l8 -4.5' fill='none' stroke='%23fff' stroke-width='3px'/%3E%3Cpath d='M12 12v9' fill='none' stroke='%23fff' stroke-width='3px'/%3E%3Cpath d='M12 12l-8 -4.5' fill='none' stroke='%23fff' stroke-width='3px'/%3E%3Cpath d='M12 12l8 4.5' fill='none' stroke='%23fff' stroke-width='3px'/%3E%3Cpath d='M12 3v9' fill='none' stroke='%23fff' stroke-width='3px'/%3E%3Cpath d='M12 12l-8 4.5' fill='none' stroke='%23fff' stroke-width='3px'/%3E%3C/svg%3E"); background-size: .65em; } .box.blue { background-color: #deebf9; color: #004085; } .box.red:before { background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M12 2c5.523 0 10 4.477 10 10a10 10 0 0 1 -19.995 .324l-.005 -.324l.004 -.28c.148 -5.393 4.566 -9.72 9.996 -9.72zm.01 13l-.127 .007a1 1 0 0 0 0 1.986l.117 .007l.127 -.007a1 1 0 0 0 0 -1.986l-.117 -.007zm-.01 -8a1 1 0 0 0 -.993 .883l-.007