/* DOWNLOAD BOX */ .downloadbox { border: 1px solid var(--border); justify-self: flex-start; margin: 1.5em 0; padding: .5em 1em 1em; transition: border-color .3s, color .3s; width: fit-content; } .downloadbox .inner { gap: 1em; margin-top: .75em; } .downloadbox .icon { max-height: 4em; max-width: 4em; } .downloadbox .noimg { padding: 1em; } .downloadbox .noimg svg { height: 2.25em; width: 2.25em; } .downloadbox .icon, .downloadbox .go { flex-shrink: 0; } .downloadbox .info { line-height: 1.6em; margin-top: -3px; } .downloadbox .go { margin-$startSide: 1.5em; } .downloadbox :is(button, .button) { display: inline-block; margin: 0; }
/* SYNTAX HIGHLIGHTER */ pre, pre code { overflow: auto; hyphens: none; -ms-hyphens: none; -webkit-hyphens: none; user-select: text; -khtml-user-select: text; -moz-user-select: text; -ms-user-select: text; -webkit-user-select: text; } pre { direction: ltr; margin: 1.5rem 0; text-align: left; white-space: pre; tab-size: 4; -moz-tab-size: 4; -o-tab-size: 4; } .tabs.syntax pre { background-color: transparent; border-radius: 0; margin: 0; padding: 0; } pre:before { content: '</>'; display: block; left: 0; right: 0; top: 0; } pre:before, .tabs.syntax li { font-size: .75em; padding: .65rem 1.25rem; } pre:before, .tabs.syntax ul, .tabs.syntax pre i.copy { background-color: var(--synHead); } .tabs.syntax pre:before { display: none; } .tabs.syntax pre i.copy:before { bottom: 0; right: 0; } pre.css:before { content: '.css'; } pre.html:before { content: '.html'; } pre.js:before { content: '.js'; } pre.jquery:before { content: '.jQuery'; } pre.php:before { content: '.php'; } pre:after { content: attr(data-copy); bottom: 0; left: 0; opacity: 0; right: 0; top: 0; visibility: hidden; } pre.copied { z-index: 2; } pre i.copy { border: 1px solid #c8ccd7; box-shadow: 3px 3px 2px #bec3d1; flex-direction: row-reverse; gap: .25rem; padding: 0 .5em; right: 1rem; top: .4rem; transition: background-color .3s, border .3s, box-shadow .3s, right .1s, top .1s; } [data-theme="dark"] pre i.copy { border-color: #3a424f; box-shadow: 3px 3px 2px #1f1f1f; } pre i.copy:hover { box-shadow: 0 0 transparent; right: .9rem; top: .5rem; } pre i.copy:before { background: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M7 7m0 2.667a2.667 2.667 0 0 1 2.667 -2.667h8.666a2.667 2.667 0 0 1 2.667 2.667v8.666a2.667 2.667 0 0 1 -2.667 2.667h-8.666a2.667 2.667 0 0 1 -2.667 -2.667z' stroke='%231f1f1f' stroke-width='1.5px'/%3E%3Cpath d='M4.012 16.737a2.005 2.005 0 0 1 -1.012 -1.737v-10c0 -1.1 .9 -2 2 -2h10c.75 0 1.158 .385 1.5 1' stroke='%231f1f1f' stroke-width='1.5px'/%3E%3C/svg%3E") center / .9em no-repeat; height: .9em; width: .9em; } [data-theme="dark"] pre i.copy:before { background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M7 7m0 2.667a2.667 2.667 0 0 1 2.667 -2.667h8.666a2.667 2.667 0 0 1 2.667 2.667v8.666a2.667 2.667 0 0 1 -2.667 2.667h-8.666a2.667 2.667 0 0 1 -2.667 -2.667z' stroke='%23dbdbdb' stroke-width='1.5px'/%3E%3Cpath d='M4.012 16.737a2.005 2.005 0 0 1 -1.012 -1.737v-10c0 -1.1 .9 -2 2 -2h10c.75 0 1.158 .385 1.5 1' stroke='%23dbdbdb' stroke-width='1.5px'/%3E%3C/svg%3E"); } pre i.copy:after { content: 'Copy'; font-style: normal; } .tabs.syntax pre i.copy:after { bottom: -.25em; } pre i.copy:hover::after { right: 4em; } .tabs.syntax pre i.copy:hover:after { right: 3.5em; } .tabs.syntax pre i.copy { top: 1rem; } .tabs.syntax pre i.copy:hover { top: 1.1rem; } .tabs.syntax i.copy:hover { border-color: #c8ccd7; padding: 0 .5em; } [data-theme="dark"] .tabs.syntax i.copy:hover { border-color: #3a424f; } pre code { max-height: 300px; line-height: 1.5em; padding: 1em 1.5em; } pre .num { background-color: rgba(10, 10, 10, .05); counter-reset: pre; float: left; height: 100%; line-height: 1.7em; opacity: .45; padding: 1em 1.5em; text-align: right; } [data-theme="dark"] pre .num { background-color: rgba(225, 225, 225, .05); opacity: .35; } .num i { display: block; font-style: normal; } .num i:before { content: counters(pre, "."); counter-increment: pre; }
/* BADGE */ .badge { font-size: .6em; vertical-align: super; } .badge.green { background-color: #28a745; } .badge.blue { background-color: #007bff; } .badge.red { background-color: #dc3545; } .badge.yellow { background-color: #ffc107; color: #212529; }
/* COLUMN */ .column { border-$startSide: 3px solid var(--border); gap: 4em; grid-template-columns: 1fr 1fr; padding-$startSide: 3em; text-align: justify; } .column.noborder { border: 0; padding: 0; } .column .content :is(h1, h2, h3, h4, h5), .column .content p { margin-top: 0; } .column .content p:last-child { margin-bottom: 0; }
/* DROPCAP */ .drop { float: $startSide; font-size: 3.25em; font-size: clamp(3em, 3.4375em + .2734vw, 3.25em); line-height: .575em; line-height: clamp(.525em, 1.4375em + .2734vw, .575em); margin-$endSide: .2em; margin-top: .275em; }
/* WIDGET */ .widget .title, .widget-title { font-size: 1rem; margin-bottom: 1.25em; margin-top: 0; } .widget-top { gap: 2rem; margin-bottom: 1.25em; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; } .widget-top .widget-title { margin-bottom: 0; } :is([class*="custom-post"]) .title-label { min-width: 25%; text-align: $endSide; } .Blog .widget-title span:first-child, #comments h3, .post-filter .all { text-transform: capitalize; } aside .widget .widget-content, main .section:not(.no-items), #main .widget:not(:last-of-type), .middle .section:not(.no-items), .custom-post-1 .widget:not(:last-of-type) .widget-content, .custom-post-2 .widget:not(:last-of-type) .widget-content, .custom-post-3 .widget:not(:last-of-type) .widget-content, .custom-post-4 .widget:not(:last-of-type) .widget-content, .contact-form-widget, [class*="custom-post"] :not(.widget)[id*="HTML"] { margin-bottom: 3rem; } [data-card="1"] aside .widget-content, [data-card="2"] .PopularPosts .widget-content, aside .profile-inner, aside .contact-form-widget { padding: 1rem 1.25rem; } aside .widget-content .PopularPosts { border-top-$startSide-radius: 10px; border-top-$endSide-radius: 10px; } .Image .caption { display: block; margin-top: .5rem; }
/* HAMBURGER MENU */ .ham svg { vertical-align: -5px; } .lightbox, .ablock { background-color: rgba(10, 10, 10, .5); backdrop-filter: blur(7px); -webkit-backdrop-filter: blur(7px); } .cover { background-color: rgba(10, 10, 10, .25); backdrop-filter: blur(2px); -webkit-backdrop-filter: blur(2px); } [data-theme="dark"] .cover { background-color: rgba(7, 7, 7, .35)' } .cover, .lightbox { $startSide: 0; top: 0; height: 100vh; height: -webkit-fill-available; width: 100vw; width: -webkit-fill-available; transition: all .2s ease-in-out; -webkit-transition: all .2s ease-in-out; }
/* HEADER */ .ignSquircle, .ignSquircle svg { max-height: 0; opacity: 0; max-width: 0; z-index: -1; } header, header > .inner { height: $(header.height); } header { top: 0; width: 100%; z-index: 3; } [data-card="2"] header { border-bottom: 1px solid var(--border); } header > .inner { padding: 1rem; } [data-card="2"] header > .inner, [data-card="2"] .second-menu .linklist { padding-$endSide: 0; padding-$startSide: 0; } header > .inner { gap: 3rem; } header.shadow { box-shadow: 0 10px 10px rgba(0, 0, 0, .3); } .header { margin-$startSide: auto; margin-$endSide: auto; } .Header { max-width: 360px; } .Header h1, .Header h2 { font-size: 1.5rem; font-weight: 400; line-height: 2rem; text-overflow: ellipsis; text-transform: uppercase; } .Header img { max-height: 30px; max-width: 100%; width: auto; } .Header h1::first-letter, .Header h2::first-letter { background-color: var(--primary); border-radius: 5px; color: var(--invertColor); line-height: 0px; margin-$endSide: 3px; padding: 0 5px; }
/* MENU */ .menu { flex-grow: 1; } .nav a, .nav .dropdown span { padding: 0 1.25rem; } .nav li { line-height: $(header.height); } .nav li:hover, .second-menu .linklist a:hover { background-color: rgba(10, 10, 10, .035); } .nav > ul > li:hover::before, .nav > ul > li.dropdown.open:before { content: ''; bottom: 0; height: 100%; $startSide: 0; position: absolute; $endSide: 0; width: 100%; z-index: -1; } [data-theme="dark"] .nav li:hover, [data-theme="dark"] .second-menu .linklist a:hover { background-color: rgba(200, 210, 220, .02); } .nav li li { line-height: calc($(header.height) - 10px); } .nav ul ul { $startSide: 0; } .nav ul ul, .bookmark-wrapper { top: $(header.height); } .nav ul ul:before { border-color: transparent; border-style: solid; border-width: 0 8.5px 8.5px; border-bottom-color: var(--light); height: 0; $startSide: 15px; position:absolute; top: -8px; width: 0; z-index:1; } .nav ul ul li:hover, .me li:hover { background-color: rgba(10, 10, 10, .05); } .nav ul ul li:first-child { border-radius: 7px 7px 0 0; } .nav ul ul li:last-child { border-radius: 0 0 7px 7px; } .nav ul ul ul { $startSide: 100%; top: 0; } .nav ul ul ul:before { border-bottom-color: transparent; border-right-color: var(--postBg); border-width: 8.5px 8.5px 8.5px 0; $startSide: -8px; } .nav .dropdown .dropdown.open { height: auto !important; } .nav .dropdown span:after, .comment-inner .input-expand:checked ~ .comment-expand:after, .hier .haspost summary:after { transform: rotate(90deg); -webkit-transform: rotate(90deg); } .nav .dropdown span:after, .comment-expand:after, .hier .haspost summary:after { content: '\203A'; font-weight: 400; margin-$startSide: .75rem; transition: transform .2s linear; -webkit-transition: transform .2s linear; } .nav .dropdown:hover span:after, .comment-expand:after, .hier .haspost[open] summary:after { transform: rotate(270deg); -webkit-transform: rotate(270deg); } .nav .dropdown .dropdown span:after { margin-top: -3px; transform: rotate(0deg); -webkit-transform: rotate(0deg); } .nav ul > li > ul > li:last-of-type > a { border-radius: 0 0 7px 7px; } .nav svg, .second-menu .linklist svg { margin-$endSide: .5rem; }
/* SEARCH */ input.search-input { background-color: var(--bg-75); height: 40px; $startSide: 0; $endSide: 0; padding-$endSide: 3.25rem; padding-$startSide: 1.25rem; transform: scaleX(0); -webkit-transform: scaleX(0); transform-origin: $endSide top; -webkit-transform-origin: $endSide top; width: calc(100% - 44px); } [data-card="2"] input.search-input { width: calc(100% - 2rem); } .search button { background-color: transparent; box-shadow: none; line-height: 0; margin: 0; padding: 0; } .search .check:checked ~ input.search-input { transform: scaleX(1); -webkit-transform: scaleX(1); z-index: 2; } .search-close { $endSide: 0; top: 0; z-index: 4; } .search-close svg { height: .75rem; width: .75rem; } .search-close line { stroke: var(--tx-75); stroke-width: 3px; } .search-close.squircle-hover:before { border-radius: 100px; clip-path: unset; min-height: unset; min-width: unset; transform: scale(1.25); -webkit-transform: scale(1.25); }
/* TOOL ICON */ .tool { gap: 1.25rem; } .squircle-hover:before { background: rgba(10, 10, 10, .065) radial-gradient(circle, transparent 100%, rgba(10, 10, 10, .065) 100%) center; clip-path: url(#ignielSquircle); $startSide: 0; $endSide: 0; top: 0; bottom: 0; opacity: 0; min-height: 22px; min-width: 22px; visibility: hidden; transform: scale(1.65); -webkit-transform: scale(1.65); transition: all .2s linear; } [data-theme="dark"] .tool label:before, [data-theme="dark"] .search-close:before { background: rgba(10, 10, 10, .15) radial-gradient(circle, transparent 100%, rgba(10, 10, 10, .15) 100%) center; } .squircle-hover:hover::before, #ham:checked ~ header .tool .ham .squircle-hover:before, #bookmark:checked ~ label:before { opacity: 1; visibility: visible; }
/* MODE */ .mode .h path:nth-child(2) { stroke-width: 2px; }
/* BOOKMARK */ .bookmark-inner ul { flex-direction: column; } .bookmark-inner ul, .bookmark-inner li, .ignielBookmarks li { gap: 1.5rem 1rem; } .bookmark path, .bm path { fill: transparent; } .bookmark-wrapper { max-height: 85vh; min-width: 320px; max-width: 480px; overflow: auto; $endSide: 0; width: max-content; } .bookmark-wrapper:before { $endSide: 6.75rem; } .bookmark-title { font-weight: 800; position: sticky; position: -webkit-sticky; top: 0; z-index: 1; } .bookmark-inner { max-height: 100vh; } .bookmark-inner, .bookmark-title { padding: 1rem 1.25rem; } .post-info-right .ignielSquircle { padding: .625rem; } .bm-thumb { flex-shrink: 0; line-height: 0; } .bm-thumb img { max-height: 50px; max-width: 50px; } .post-body .bm-thumb, .post-body .bm-thumb img { max-height: 100%; max-width: 100%; } .bm-title { flex-grow: 1; } .bm-delete { margin-$startSide: 1rem; } .bm-delete:hover path { stroke: #ff6684; } .bm-delete path, .multi .post-comments path { stroke: var(--tx-50); } .bm-more { border-top: 1px solid var(--border); padding-top: 1rem; text-align: center; } .ignielBookmarks ul { flex-wrap: wrap; gap: 2rem 6rem; } .ignielBookmarks li { width: calc(50% - 3rem); } .ignielBookmarks ul, .ignielBookmarks li { padding-inline-start: 0; } .multi .bm { $endSide: .65rem; top: .75rem; } .multi .bm-icon { background-color: rgba(10, 10, 10, .5); padding: .5rem; } .multi .bm-icon:hover { background-color: rgba(255,255,255,1); } .multi .bm input:checked ~ .bm-icon { background-color: rgba(255,255,255,.5); } .bm input:checked ~ .bm-icon path { fill: var(--primary); stroke: var(--primary); } .bm input:checked ~ .bm-icon path.y { fill: none; stroke: var(--invertColor); } .bookmark-loading { padding: .5rem; text-align: center; } .bookmark-loading svg { animation: ignielSpin .75s linear infinite normal; -webkit-animation: ignielSpin .75s linear infinite normal; }
/* LINKS (PROFILE NAV) */ .links { min-width: 200px; max-width: 250px; $endSide: 5px; top: $(header.height); } [data-card="2"] .links { $endSide: -10px; } .links:before { $endSide: 11px; } .links:before, .bookmark-wrapper:before { border-color: transparent; border-bottom-color: var(--bg-75); border-style: dashed dashed solid; border-width: 0 8.5px 8.5px; height: 0; top: -8px; width: 0; } .links .head { border-radius: 7px 7px 0 0; padding: 1rem; } .links .ava { max-height: 50px; max-width: 50px; min-height: 50px; min-width: 50px; margin-$endSide: 1rem; object-fit: cover; } .menu .follow a:before { content: '\00D7'; font-size: initial; margin-$endSide: .5rem; transform: rotate(45deg); vertical-align: -1px; } .links .follow line { stroke-width: 4px; } .links .head .info { flex-direction: column; } .me a { padding: .75rem 1rem; } .me svg { margin-$endSide: .75rem; } .me ul { margin: .5rem 0; } .me li { padding: 0; } .social { border-radius: 0 0 7px 7px; padding: 0 .5rem; } .social a { flex-grow: 1; padding: 1rem .5rem; } .fb:hover path { fill: #3a579a; } .ig:hover path { fill: #9c27b0; } .tt:hover path { fill: var(--tx-100); } .twt:hover path { fill: #000; } .yt:hover path { fill: #ff0000; }
/* LINK LIST */ .second-menu:not(.no-items) { transition: background-color .3s, border-color .3s; } [data-card="1"] .second-menu:not(.no-items) { border-top: 1px solid var(--border); } [data-card="2"] .second-menu:not(.no-items) { border-bottom: 1px solid var(--border); } .second-menu .linklist { overflow: hidden; } .second-menu .linklist ul { overflow-x: auto; overflow-y: hidden; white-space: nowrap; } .second-menu .linklist li { display: inline-block; vertical-align: middle; } .second-menu .linklist a { padding: 1.25rem 2rem; transition: background-color .3s, color .3s; } .footer .linklist li { gap: .5rem; } .footer .linklist li:not(:last-child) { margin-bottom: .5rem; }
/* SLIDER */ .slider { direction: ltr; } .slider ul { margin: 0; padding: 0; } .slider .glide { height: 120px; } .slider .grid, .slider .swipe, .billboard { margin-top: 2rem; } .slider .grid ul { grid-gap: 10px; grid-template-columns: 1.25fr 1fr 1fr; } .slider .grid li:first-child { grid-area: 1 / 1 / 3 / 1; max-height: 370px; } .slider .grid li:not(:first-child) { max-height: 180px; } .slider-inner { bottom: 2.5rem; $startSide: 1.5rem; $endSide: 1.5rem; } .glide .slider-inner { bottom: 3.5rem; } .slider .grid li:first-child .slider-inner { bottom: 1.5rem; $startSide: 2rem; $endSide: 2rem; } .slider .grid li:not(:first-child) .slider-inner { bottom: 1.25rem; $startSide: 1.25rem; $endSide: 1.25rem; } .slider .grid li:first-child .slider-text { font-size: 1.25rem; line-height: 1.65em; } .slider-text { -webkit-line-clamp: 2; } .slider .swipe .swipe-inner li { border-radius: 12px; flex: 1 0 calc(100vw / 3); max-width: calc(100vw / 3); min-width: 420px; scroll-snap-align: start; scroll-snap-stop: always; } .slider .swipe img { max-height: 240px; } .slider .swipe .slider-inner { bottom: 1.25rem; } .slider .swipe .slider-text { white-space: normal; } .slider-label { margin-bottom: 1.25em; } .slider-label >*, .custom-post-4 .post-labels >* { display: inline-block; font-size: inherit; line-height: inherit; margin: 0; padding: .35em .75em; } .slider-text, .grid-inner .expand:after, .custom-post-4 .post-title { text-shadow: 0 2px 10px #272733, 0 1px 1px rgba(10, 10, 10, .5); } .glide .slider-thumb { max-height: 360px; } .slider-thumb:after, .custom-post-4 .snippet-thumb:after { background: linear-gradient(to bottom, transparent, rgba(10, 10, 10, .5)); background: -webkit-linear-gradient(top, transparent, rgba(10, 10, 10, .5)); bottom: 0; width: 100%; height: 50%; }
