/* CUSTOM 1 */ .custom-post-1 .skl, .related-bottom-inner.gd .skl { grid-template-columns: 1fr 1fr 1fr; } [data-grid="2"] .custom-post-1 .skl { grid-template-columns: 1fr 1fr; } [data-grid="3"] #custom-post-1 .skl >*:nth-child(n+4), .related-bottom-inner.gd .skl >*:nth-child(n+4) { display: none; } [class*="-arrow"] .arrow { border: 1px solid var(--border); bottom: 0; font-size: 1rem; height: 1rem; margin: auto; padding: 1rem; top: 0; width: 1rem; } [class*="-arrow"] .arrow:hover { box-shadow: none; } .arrow.prev { $startSide: -1em; } .arrow.next { $endSide: -1em; }
