/* CUSTOM 3 */ .swipe-inner { flex-wrap: nowrap; } .swipe-inner >* { scroll-snap-align: start; } .custom-post-3 .arrow { top: -5rem !important; } .swipe-inner, .carousel-inner { overflow-x: scroll; overflow-y: hidden; overscroll-behavior-x: contain; scroll-snap-type: x mandatory; white-space: nowrap; -webkit-overflow-scrolling: touch; } .custom-post-3 .article, .custom-post-3 .skeleton, .custom-post-4 .skeleton, .custom-post-4 li { flex: 1 0 240px; max-width: 240px; scroll-snap-align: unset; white-space: normal; } .swipe-inner, .carousel-inner { flex: 0 0 auto; } .custom-post-3 .snippet-thumb, .custom-post-4 .snippet-thumb { max-width: 240px; }
