/* 404 NOT FOUND */ .not-found { flex-wrap: wrap; max-height: 100vh; margin: 3rem auto; } .not-found h2 { font-size: 2.5rem; line-height: 4rem; margin-bottom: 2rem; margin-top: 0; } .notfound-inner:before { content: '404'; $endSide: 0; font-size: 15rem; line-height: 1em; margin: auto; opacity: .15; $startSide: 0; top: 0; white-space: nowrap; z-index: -1; } [data-theme="dark"] .notfound-inner:before { opacity: .075; } .not-found .text { margin-bottom: 2rem; } .notfound-outer { flex-basis: 100%; flex-grow: 1; margin: 0 3rem; width: calc(100% - 6rem); } .not-found .button { margin-top: 3rem; }
/* MAIN */ main { max-width: $(width.main + grid.gap); min-width: 0; width: 100%; } /* @supports (overflow: clip) { main {overflow: clip} } */ [data-card="2"] main { max-width: calc($(width.main + grid.gap) + 20px); } .page main { max-width: 100%; } main.not-found { max-width: 900px; width: 100%; } #main { flex-grow: 1; } [data-card="2"] main .section:not(.no-items), [data-card="2"] .middle .section:not(.no-items) { margin-bottom: 4rem; } #main #HTML7 { margin-bottom: $(grid.gap); } .blog-posts, .custom-post-1 .skl, .swipe-inner, .related-bottom-inner.gd .skl, .related-bottom-inner.gd:not(.noimage) ul { gap: $(grid.gap); } [data-card="2"] .blog-posts, [data-card="2"] .custom-post-1 .skl, [data-card="2"] .swipe-inner, [data-card="2"] .related-bottom-inner.gd .skl, [data-card="2"] .related-bottom-inner.gd:not(.noimage) ul { gap: calc($(grid.gap) + 15px) calc($(grid.gap) + 10px); } .blog-posts > .article, .related-bottom-inner.gd:not(.noimage) li { width: calc((100% / 3) - calc($(grid.gap) / 1.5)); } [data-card="2"] .blog-posts > .article, [data-card="2"] .related-bottom-inner.gd:not(.noimage) li { width: calc((100% / 3) - calc(calc($(grid.gap) + 10px) / 1.5)); } [data-card="2"][data-grid="2"] .blog-posts > .article { width: calc((100% / 2) - 15px); } [data-grid="2"] .blog-posts > .article { width: calc((100% / 2) - 10px); } [data-card="1"] .Blog .article, [data-card="1"].single .related-bottom-inner.gd .article, [data-card="1"] .custom-post-1 .article, [data-card="1"] .custom-post-3 .article { padding: 0 1rem 1rem; } .single .blog-posts > .article { overflow: unset; width: 100%; } [data-card="1"].single .blog-posts > .article { padding: 1rem 1.5rem; } [data-card="2"].single .blog-posts > .article { width: 100%; } .swipe-up { opacity: 0; transform: scale(.85) translateY(1.25rem); } .swipe-up.swiped { opacity: 1; transform: scale(1) translateY(0); } .infeed { width: 100%; } .igniplex { justify-content: flex-start; padding-top: $(grid.gap); } [data-card="2"] .igniplex { padding-top: 2rem; } .post-filter { margin-bottom: 1.5rem; } .no-post .text { margin: 2rem 0; } .no-post svg, .not-found svg { height: 1.25rem; width: 1.25rem; margin-$endSide: .25rem; vertical-align: -3px; }
