/* POST BODY */ .post-body { /* font-size: clamp(1rem, .9679rem + .1321vw, 1.1rem); line-height: clamp(1.75rem, 1.6759rem + .3241vw, 2rem); */ font-size: 1.0715rem; line-height: 1.75em; transition: font-size .3s; } .single .post-body, .comment-content { font-size: 1.175rem; } .post-body h2 { font-size: 1.5em; } .post-body h3 { font-size: 1.33em; } .post-body h4, .feat-title, .slider-text { font-size: 1.15em; } .post-body h2:target:after, .post-body h3:target:after, .post-body h4:target:after, .post-body h5:target:after { content: '#'; color: var(--primary); margin-$startSide: .5rem; } .post-body p, .post-body > ol, .post-body > ul, .toc { margin: 1em 0; } .post-body :not(.related-middle, .ignielBookmarks, .box) a:not(.button, [class*="btn"], [class*="tx"], :hover), .comment-content a, #sitemap2 a:hover { color: var(--postLink); } .post-body figure:not(.h) { display: table; } .post-body figure, details, table, .table, .tabs, .accordion.multi, .gallery, .column { margin: 1.5em auto; } .post-body figcaption { border-bottom: 1px solid var(--border); display: table; margin-top: .5rem; padding-bottom: 1rem; } .post-body button { font-size: inherit; } .post-body .separator a { margin: 0 !important; } .post-info { flex-grow: 1; gap: .75rem; margin-bottom: 1rem; overflow: hidden; } .single .post-info { margin-bottom: 1.5rem; margin-top: 1.5rem; overflow: unset; } .post-info-author { align-self: flex-start; } .post-info-author, .post-info-author img { height: 2.75rem; width: 2.75rem; flex-shrink: 0; } .post-info-left { margin-$endSide: 2rem; overflow: hidden; } .post-info-left-top { gap: .65em; white-space: nowrap; } .post-info-left-top strong { overflow: hidden; text-overflow: ellipsis; } .post-info-left:has(.time-update) { align-self: stretch; } .post-info-right { align-self: flex-start; gap: .75rem; margin-$startSide: auto; white-space: nowrap; } .post-info-right svg { flex-shrink: 0; } .nothumb:before { content: ''; -webkit-mask: var(--fallbackIcon) center / 2rem no-repeat; mask: var(--fallbackIcon) center / 2rem no-repeat; background-color: var(--primary); height: 100%; line-height: normal; text-align: center; transition: background-color .3s; width: 100%; }
/* READ TIME */ .read-time:before, .pop-content .post-labels:after { content: ''; background-color: var(--tx-50); display: inline-block; height: 3px; margin-$endSide: .25em; vertical-align: 2px; width: 3px; }
/* LETTER */ .letter fieldset { border: 0; $endSide: 0; max-height: 0; opacity: 0; overflow: hidden; padding: 0; top: 3.25rem; transition: max-height .2s, opacity .7s, visibility .7s, background-color .2s; -webkit-transition: max-height .2s, opacity .7s, visibility .7s, background-color .2s; visibility: hidden; white-space: nowrap; } #letter:checked ~ main .letter fieldset { max-height: 100vh; opacity: 1; transition: max-height .5s, opacity .1s, visibility .1s, background-color .2s; -webkit-transition: max-height .5s, opacity .1s, visibility .1s, background-color .2s; visibility: visible; z-index: 1; } .letter fieldset label { gap: .5rem; padding: .85rem 1rem; } .letter fieldset svg { height: 1.25rem; width: 1.25rem; } [data-letter="smaller"] .single .post-body { font-size: 1rem; } [data-letter="bigger"] .single .post-body { font-size: 1.35rem; } #letter:checked ~ .cover-letter { transform: translateY(0); -webkit-transform: translateY(0); visibility: visible; }
/* THEME COLOR */ .theme-color fieldset { border: 0; $endSide: 0; max-height: 0; opacity: 0; overflow: hidden; padding: 0; top: 3.25rem; transition: max-height .2s, opacity .7s, visibility .7s, background-color .2s; -webkit-transition: max-height .2s, opacity .7s, visibility .7s, background-color .2s; visibility: hidden; white-space: nowrap; position: absolute; } #theme-color:checked ~ header .theme-color fieldset { max-height: 100vh; opacity: 1; transition: max-height .5s, opacity .1s, visibility .1s, background-color .2s; -webkit-transition: max-height .5s, opacity .1s, visibility .1s, background-color .2s; visibility: visible; z-index: 10; } .theme-color fieldset label { gap: .5rem; padding: .85rem 1rem; display: flex; align-items: center; cursor: pointer; } .theme-color fieldset label:hover { background-color: var(--bg-75); } .theme-color fieldset input:checked + label { background-color: var(--bg-75); font-weight: 700; } .color-blob { display: inline-block; width: 1.25rem; height: 1.25rem; border-radius: 50%; border: 1px solid var(--border); } .theme-color-label svg { width: 1.5rem; height: 1.5rem; } #theme-color:checked ~ header .theme-color .cover-theme-color, #letter:checked ~ .cover-letter { transform: translateY(0); -webkit-transform: translateY(0); visibility: visible; } /* TOC 顏色連動調整 */ .post-body .toc a { color: var(--primary) !important; filter: brightness(0.85); } /* 針對有數字的情形 */ .post-body .toc ol li::before { color: var(--primary) !important; filter: brightness(0.85); } .letter:before { padding: .25em .75em; } .letter[data-num="smaller"]:before { content: '\2013'; } .letter[data-num="bigger"]:before { content: '+'; } .elink:after { content: ''; background: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M17 7l-10 10' stroke='%23536471' stroke-width='2px'/%3E%3Cpath d='M8 7l9 0l0 9' stroke='%23536471' stroke-width='2px'/%3E%3C/svg%3E") center / 1em no-repeat; display: inline-block; height: 1em; margin-$startSide: .1em; transition: background .3s; vertical-align: -4px; width: 1em; } [data-theme="dark"] .elink:after { background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M17 7l-10 10' stroke='%239ba3b5' stroke-width='2px'/%3E%3Cpath d='M8 7l9 0l0 9' stroke='%239ba3b5' stroke-width='2px'/%3E%3C/svg%3E"); }
