/* TOC */ .toc { border: 1px solid var(--border); padding: 1rem 1.5rem; } .toc ol, .toc-overlay ol, .toc ul, .toc-overlay ul { line-height: 1.75em; margin-bottom: 0; max-height: 100%; overflow: hidden; padding-$startSide: 1em; } .toc ol, .toc-overlay ol { counter-reset: toc; list-style: none; } .toc > ol, .toc-overlay > ol, .toc > ul, .toc-overlay > ul { margin-top: .75em; } .toc > ol, .toc-overlay > ol { padding-$startSide: 0; } .toc ul li, .toc-overlay ul li { list-style-type: disc; } .toc ul ul li, .toc-overlay ul ul li { list-style-type: circle; } .toc > ol, .toc > ul { transition: max-height .3s ease-in-out, margin-top .3s ease-in-out, padding-bottom .3s ease-in-out; -webkit-transition: max-height .3s ease-in-out, margin-top .3s ease-in-out, padding-bottom .3s ease-in-out; } .toc-title:after { content: ''; background: var(--primary) url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M19.9201 8.94995L13.4001 15.47C12.6301 16.24 11.3701 16.24 10.6001 15.47L4.08008 8.94995' stroke='%23fff' stroke-width='2px'/%3E%3C/svg%3E") center / .75em no-repeat; height: 1.25em; flex-shrink: 0; font-weight: 400; transform: rotate(180deg); -webkit-transform: rotate(180deg); width: 1.25em; } #toc:checked ~ .toc-title:after { transform: rotate(0); -webkit-transform: rotate(0); } .toc ol li:before, .toc-overlay ol li:before { content: counters(toc, ".") ". "; counter-increment: toc; } #toc:checked ~ ol, #toc:checked ~ ul { margin-bottom: 0; margin-top: 0; max-height: 0; transition: max-height .2s cubic-bezier(0,1,0,1), margin-top .2s ease-out, padding-bottom .2s cubic-bezier(0,1,0,1); -webkit-transition: max-height .2s cubic-bezier(0,1,0,1), margin-top .2s ease-out, padding-bottom .2s cubic-bezier(0,1,0,1); } .toc-icon { max-width: 0; margin-$startSide: -1rem; padding: 0; transition: max-width .2s cubic-bezier(0,1,0,1), margin-$startSide .2s, padding .2s, background-color .3s; -webkit-transition: max-width .2s cubic-bezier