/* YouTube Lazy */ .youtubelazy { margin: 1.5rem auto; padding-bottom: calc((9/16) * 100%); } .youtubelazy figure { margin: 0; } .youtubelazy figure:before { background: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M17 20H7C4 20 2 18 2 15V9C2 6 4 4 7 4H17C20 4 22 6 22 9V15C22 18 20 20 17 20Z' fill='%23e93f36'/%3E%3Cpath d='M11.4196 9.49009L13.8896 10.9701C14.8296 11.5401 14.8296 12.4601 13.8896 13.0301L11.4196 14.5101C10.4196 15.1101 9.59961 14.6501 9.59961 13.4801V10.5101C9.59961 9.35011 10.4196 8.89009 11.4196 9.49009Z' fill='%23fff'/%3E%3C/svg%3E") center / 6rem no-repeat; color: #e93f36; letter-spacing: 1px; padding-top: 7.5rem; } .youtubelazy figure:hover:before { opacity: .75; } .youtubelazy figure:before, .youtubelazy img, .youtubelazy iframe { bottom: 0; $startSide: 0; $endSide: 0; top: 0; } .youtubelazy iframe { height: 100%; width: 100%; }
