/* RELATED MIDDLE */ .igniplexTengah, .aTop:has(*), .aBtm:has(*), .post-body .separator { margin: 1.5rem 0; } .related-middle { border-bottom: 1px solid var(--border); border-top: 1px solid var(--border); padding: 1.5rem 0; } [data-card="2"] .related-middle { border: 1px solid var(--border); padding: 1.5rem; } .related-middle .widget-title { line-height: normal; margin-bottom: 1.5rem; } .noimage .related-middle-inner { padding: 0 1.5em; } .related-middle ul { gap: 2rem 3rem; grid-template-columns: repeat(2, 1fr); } .related-middle.noimage li { padding: .5em 0; } .related-middle.noimage li:first-of-type { padding-top: 0; } .related-middle.noimage li:last-of-type { padding-bottom: 0; } .related-middle.noimage li:before { content: '\203A'; } .related-middle-title { line-height: 1.75; }
/* RELATED BOTTOM */ .related-bottom-inner:not(.gd) ul { gap: calc($(grid.gap) + 10px); grid-template-columns: repeat(2, 1fr); } .related-bottom .noimage ul { counter-reset: relatedBottom; } .related-bottom li, .related-bottom-inner.gd.noimage ul, .related-bottom-inner.noimage:not(.gd) ul { gap: 1.5rem; } .related-bottom .noimage.nosnippet li { column-gap: 10px; } .related-bottom .noimage li:before { align-items: flex-start; content: counter(relatedBottom)'.'; counter-increment: relatedBottom; height: auto; flex-shrink: 0; } .related-bottom-inner.gd.noimage li { width: calc((100% / 2) - calc(1.5rem / 2)); } .related-bottom-thumb { flex-shrink: 0; } .related-bottom .post-snippet:after { content: '...'; } [data-card="1"] .related-bottom-inner:not(.gd), [data-card="1"] .related-bottom-inner.gd.noimage ul { padding: 1.5rem; } .related-bottom-inner.noimage svg { flex-shrink: 0; } .related-bottom-inner.noimage .post-inner { margin-top: 0; -webkit-line-clamp: unset; } .related-bottom .right { flex: 1 0 auto; } .related-bottom .post-timestamp { line-height: normal; margin-bottom: .5rem; }
