/* SHARE BOX */ .share-box { max-height: 90vh; overflow: auto; padding: 1.5rem; z-index: 5; } .share-box svg { height: 1.75rem; width: 1.75rem; } .share-box .widget-title { margin-bottom: 0; } .share-box-top label { font-size: 2rem; line-height: 0; } .share-box-content { gap: 2rem 1.5rem; grid-template-columns: repeat(4, 1fr); margin-top: 2rem; } .share-box-content a, .share-box-content span { border-radius: 15px; display: block; padding: 1.5rem; width: fit-content; } .share-box-content i { margin-top: .5rem; } .share-copy-input { flex: 1 0 auto; padding: 1rem 4.5rem 1rem 1rem; text-overflow: ellipsis; white-space: nowrap; width: 100%; } .share-copy-info { margin-top: 0; max-height: 0; overflow: hidden; text-align: center; transition: max-height .2s, margin-top .2s; } .share-copy-info.success { margin-top: 2rem; max-height: 100vh; transition: max-height .2s, margin-top .2s; }
/* TABS */ .tabs.syntax { overflow: hidden; } .tabs:not(.syntax) { border: 1px solid var(--border); } .tabs.vertical { flex-wrap: nowrap; } .tabs ul { overflow-x: auto; overflow-y: hidden; white-space: nowrap; } .tabs:not(.syntax) ul { border-bottom: 1px solid var(--border); gap: 1em; margin-bottom: 1.25em; } .tabs.vertical ul { border-bottom: 0; border-right: 1px solid var(--border); gap: 0; flex-direction: column; flex-shrink: 0; margin-bottom: 0; max-height: calc(100vh - 150px); max-width: 25%; overflow-x: hidden; overflow-y: scroll; white-space: normal; } .tabs li { padding: .75em 1.5em; } .tabs.syntax li { transition: background-color .3s, border-color .3s, color .3s; } .tabs.syntax .content { border-bottom-$startSide-radius: 7px; border-bottom-$endSide-radius: 7px; border-top-$startSide-radius: 0; } .tabs.syntax .current { border-bottom: 2px solid var(--tx-100); } [data-theme="dark"] .tabs.syntax .current { border-bottom } .tabs .current { border-bottom: 2px solid var(--primary); } .tabs.vertical .current { border-bottom: 0; border-$endSide: 2px solid var(--primary); } .tabs:not(.syntax) .content { padding: 0 1.5rem 1.25rem; } .tabs.vertical .content { padding: 1rem 1.25rem; } .tabs .arrow.prev { background: linear-gradient(90deg, transparent, var(--postBg), var(--postBg)); background: -webkit-linear-gradient($endSide, transparent, var(--postBg), var(--postBg)); $startSide: 0; padding-$startSide: 1rem; padding-$endSide: 3rem; } [data-card="2"] .tabs .arrow.prev { background: linear-gradient(90deg, transparent, var(--bodyBg), var(--bodyBg)); background: -webkit-linear-gradient($endSide, transparent, var(--bodyBg), var(--bodyBg)); } .tabs .arrow.next { background: linear-gradient(270deg, transparent, var(--postBg), var(--postBg)); background: -webkit-linear-gradient($startSide, transparent, var(--postBg), var(--postBg)); $endSide: 0; padding-$endSide: 1rem; padding-$startSide: 3rem; } [data-card="2"] .tabs .arrow.next { background: linear-gradient(270deg, transparent, var(--bodyBg), var(--bodyBg)); background: -webkit-linear-gradient($startSide, transparent, var(--bodyBg), var(--bodyBg)); } .tabs .arrow { padding-top: .5em; top: .25em; }
/* ACCORDION */ details, .accordion.multi { border: 1px solid var(--border); padding: 1em 1.25em; transition: border-color .3s, color .3s; } details summary { gap: 1em; transition: margin-bottom .3s; } .accordion.multi > details { border: 0; border-radius: 0; margin: 0; padding: 0; } .accordion.multi details:not(:last-child) { border-bottom: 1px solid var(--border); margin-bottom: 1em; padding-bottom: 1em; } details[open] > summary, .accordion.multi details[open] > summary { margin-bottom: 1em; } details:not(.spoiler) summary:after { content: '\002b'; align-self: flex-start; transform: rotate(90deg); -webkit-transform: rotate(90deg); } details[open] > summary:after, .accordion.multi details[open] > summary:after { content: '\2013'; margin-top: -3px; transform: rotate(0); -webkit-transform: rotate(0); }
/* SPOILER */ .spoiler summary { border-bottom: 1px solid transparent; margin-bottom: 0; padding-bottom: 0; transition: border-color .3s, color .3s, margin-bottom .3s, padding-bottom .3s; } .spoiler summary:after { content: 'Open'; font-size: .7em; font-weight: 400; line-height: normal; padding: .5em .75em; transition: background-color .3s, color .3s; } .spoiler[open] summary { border-bottom-color: var(--border); padding-bottom: 1rem; } .spoiler[open] summary:after { content: 'Close'; margin-top: 0; }
/* GALLERY */ .gallery img { object-fit: cover; } .caption { margin-top: .5rem; transition: background-color .3s, color .3s; } .grid .caption { margin-top: 1rem; } .gallery .swipe-inner, [data-card="2"] .gallery .swipe-inner, .carousel-inner, .grid-inner { gap: 10px; }
/* SWIPE */ .gallery.swipe img { width: calc((100% / 2) - 6rem); } .gallery.swipe.portrait img { scroll-snap-align: none; width: calc((100% / 3) - 3rem); }
/* CAROUSEL */ .carousel { overflow: hidden; } .carousel img { flex: 1 0 100%; scroll-snap-align: center; scroll-snap-stop: always; width: 100%; } [class*="-arrow"] button, .carousel span { line-height: 0; margin: 0; } .carousel-tx { top: 1em; $endSide: 1em; line-height: 0; padding: 1em .75em; } .carousel-dot { bottom: 2em; $endSide: 1em; gap: .5em; $startSide: 1em; } .carousel .dot { border: 1px solid var(--tx-50); height: .25em; padding: .25em; width: .25em; } .carousel .dot.active { border-color: var(--primary); } .carousel .arrow.prev { $startSide: 1em; } .carousel .arrow.next { $endSide: 1em; }
/* GRID */ .grid-inner { align-items: stretch; grid-template-columns: repeat(2, 1fr); grid-template-rows: 1fr 1fr; } .more .grid-inner { grid-template-columns: repeat(6, 1fr); } .grid-inner img { height: 100%; width: 100%; } .grid-inner figure:not(.h) { display: block; line-height: 0; margin: 0; } .more .grid-inner >*:first-child { grid-area: 1 / 1 / 2 / 4; } .more .grid-inner >*:nth-child(2) { grid-area: 1 / 4 / 2 / 7; } .more .grid-inner >*:nth-child(3) { grid-area: 2 / 3 / 2 / 1; } .more .grid-inner >*:nth-child(4) { grid-area: 2 / 3 / 2 / 5; } .more .grid-inner >*:nth-child(5) { grid-area: 2 / 5 / 2 / 7; } .grid-inner .expand { z-index: 1; } .grid-inner .expand:before, .grid-inner .expand:after { bottom: 0; $endSide: 0; margin: auto; $startSide: 0; top: 0; } .grid-inner .expand:before { content: ''; backdrop-filter: blur(2px); -webkit-backdrop-filter: blur(2px); } .grid-inner .expand:after { content: '+'attr(data-more); font-size: 4em; } .more .grid-inner >*:nth-child(n+6) { display: none; }
