/* ASIDE */ aside { margin-$startSide: $(grid.gap); width: $(width.aside); } [data-card="2"] aside { margin-$startSide: calc(2 * $(grid.gap)); }
/* MIDDLE */
/* FOOTER */ .footer { margin-bottom: $(grid.gap); } [data-card="2"] .footer { margin-top: 1rem; } [data-card="1"] .footer-inner { padding: 1.5rem 1.75rem; } .footer .widget-content { line-height: 1.75em; } .footers { gap: 4rem; grid-template-columns: 1fr 1fr 1fr; } .footers .widget { margin-bottom: 4rem; } .itsme { margin-top: 0; }
