/* Angular Material Icons Fallback */ .google-symbols, .mat-icon { font-family: 'Material Symbols Outlined'; font-weight: normal; font-style: normal; font-size: inherit; width: 1em; height: 1em; padding: 0; margin: 0; background: transparent; line-height: 1; letter-spacing: normal; text-transform: none; display: inline-block; vertical-align: middle; white-space: nowrap; word-wrap: normal; direction: ltr; -webkit-font-feature-settings: 'liga'; -webkit-font-smoothing: antialiased; } .mat-icon[fonticon]::before, .google-symbols[fonticon]::before { content: attr(fonticon); } /* Remove excessive padding for button containers of standard Icons */ button.mat-mdc-tooltip-trigger, button:has(> .mat-icon:only-child), .button:has(> .mat-icon:only-child) { padding: 8px; min-width: auto; line-height: 0; }
/* --- 客製化 Second Menu Hover 視覺特效 --- */ /* PS泛科學 (Navyblue) */ .second-menu .linklist a[href="https://pansci.asia/"] { transition: all 0.3s ease; } .second-menu .linklist a[href="https://pansci.asia/"]:hover { color: #000080 !important; }
/* Emmy追劇時間 (YouTube Red) */ .second-menu .linklist a[href="https://www.youtube.com/channel/UCUkwvRrpvWkocNdk9qIpRSw"] { transition: all 0.3s ease; } .second-menu .linklist a[href="https://www.youtube.com/channel/UCUkwvRrpvWkocNdk9qIpRSw"]:hover { color: #FF0000 !important; }
/* NGScience (National Geographic 著名的黃色框框) */ /* 滑鼠移入時，在文字前方生成 NG 的經典黃底方框，配上文字變黃 */ .second-menu .linklist a[href="https://www.instagram.com/natgeoscience/"] { position: relative; transition: all 0.3s ease; display: inline-flex; align-items: center; } .second-menu .linklist a[href="https://www.instagram.com/natgeoscience/"]:hover::before { content: ""; display: inline-block; width: 10px; height: 16px; border: 3px solid #FFCC00; margin-right: 6px; box-sizing: border-box; } .second-menu .linklist a[href="https://www.instagram.com/natgeoscience/"]:hover { color: #FFCC00 !important; }
/* 魔卡貓的咖啡窩 (橘貓的橘) */ .second-menu .linklist a[href="https://mochacat.pixnet.net/blog"] { transition: all 0.3s ease; } .second-menu .linklist a[href="https://mochacat.pixnet.net/blog"]:hover { color: #FF8C00 !important; }
/* 回家的光傳送門 (Coral Pink 帶發光特效) */ .second-menu .linklist a[href="https://auth.icekimo.idv.tw/login"] { transition: all 0.3s ease; } .second-menu .linklist a[href="https://auth.icekimo.idv.tw/login"]:hover { color: #F88379 !important; text-shadow: 0 0 10px rgba(248, 131, 121, 0.5); } /* === [Icekimo] SMS Bubble Style === */ .sms-thread { display: flex; flex-direction: column; gap: .75rem; margin: 1.5em 0; padding: 0; }
/* 單一訊息列 */ .sms { display: flex; flex-direction: column; max-width: 72%; gap: .2rem; }
/* 預設左邊（對方） */ .sms-left { align-self: flex-start; align-items: flex-start; }
/* 右邊（自己） */ .sms-right { align-self: flex-end; align-items: flex-end; }
/* 說話者名稱 */ .sms-name { font-size: var(--tx-sm); color: var(--tx-50); padding: 0 .75rem; }
/* 泡泡本體 */ .sms-bubble { position: relative; padding: .6rem 1rem; border-radius: 18px; line-height: 1.5em; font-size: var(--tx-md); word-break: break-word; transition: background-color .3s, color .3s; }
/* 左邊泡泡樣式 */ .sms-left .sms-bubble { background-color: var(--bg-75); color: var(--tx-100); border-bottom-left-radius: 4px; }
/* 左邊凸角（左下） */ .sms-left .sms-bubble::after { content: ''; position: absolute; bottom: 0; left: -7px; width: 0; height: 0; border: 8px solid transparent; border-top: 0; border-left: 0; border-bottom-right-radius: 2px; border-right-color: var(--bg-75); transition: border-color .3s; }
/* 右邊泡泡樣式 */ .sms-right .sms-bubble { background-color: var(--primary); color: var(--invertColor); border-bottom-right-radius: 4px; }
/* 右邊凸角（右下） */ .sms-right .sms-bubble::after { content: ''; position: absolute; bottom: 0; right: -7px; width: 0; height: 0; border: 8px solid transparent; border-top: 0; border-right: 0; border-bottom-left-radius: 2px; border-left-color: var(--primary); transition: border-color .3s; }
/* 時間戳 */ .sms-time { font-size: .7rem; color: var(--tx-50); padding: 0 .75rem; transition: color .3s; }
/* 折疊外層 */ details.sms-fold { border: 1px solid var(--border); border-radius: 7px; padding: .75rem 1rem; margin: 1.5em 0; transition: border-color .3s; }
details.sms-fold > summary { font-size: var(--tx-md); color: var(--tx-75); cursor: pointer; list-style: none; display: flex; align-items: center; gap: .5rem; transition: color .3s; }
details.sms-fold > summary::before { content: '💬'; font-size: 1rem; }
details.sms-fold[open] > summary { margin-bottom: .75rem; color: var(--primary); }
/* 手機版調整 */ @media screen and (max-width: 568px) { .sms { max-width: 88%; } } /* === [Icekimo] SMS Bubble Style End === */ /* === [Icekimo] Theme Color Switcher === */ [data-theme-color="purple"] { --primary: #6c5ce7; } [data-theme-color="pink"] { --primary: #e84393; } [data-theme-color="sand"] { --primary: #d4a373; } /* Sand 模式下的 SMS 泡泡文字修正 */ [data-theme-color="sand"] .sms-right .sms-bubble { color: var(--tx-100); } [data-theme-color="sand"] .sms-right .sms-bubble::after { border-left-color: var(--primary); }
body#layout #HTML1 .widget-content, body#layout #HTML2 .widget-content, body#layout #HTML6 .widget-content, body#layout #HTML7 .widget-content, body#layout #HTML9 .widget-content, body#layout #HTML10 .widget-content, body#layout #HTML15 .widget-content, body#layout #HTML19 .widget-content, body#layout #HTML20 .widget-content, body#layout #HTML32 .widget-content, body#layout #HTML33 .widget-content, body#layout #HTML34 .widget-content, body#layout #HTML35 .widget-content, body#layout #HTML36 .widget-content, body#layout #HTML37 .widget-content, body#layout #HTML38 .widget-content, body#layout #HTML39 .widget-content { background-color: rgba(255, 104, 93, .25); color: #333; } body#layout #HTML1 .widget-content .layout-widget-description, body#layout #HTML1 .widget-content .layout-widget-state, body#layout #HTML2 .widget-content .layout-widget-description, body#layout #HTML2 .widget-content .layout-widget-state { display: none; } body#layout #HTML1 .widget-content .layout-title, body#layout #HTML2.widget-content .layout-title { margin-left: 10px; } body#layout header .inner, body#layout footer .inner { display: block; overflow: auto; padding: 0; white-space: nowrap; } body#layout header .layout-widget-description, body#layout footer .layout-widget-description { white-space: normal; } body#layout #header, body#layout main, body#layout #HTML3, body#layout #footer1, body#layout #footer2, body#layout #footer3, body#layout #HTML30 { float: left; } body#layout #settings, body#layout #HTML4, body#layout #HTML30, body#layout .igniplex { display: inline-block; } body#layout #header, body#layout .menu, body#layout .footers, body#layout .credit { clear: both; } body#layout { padding: 100px 20px 20px; } body#layout div.section { border-radius: 7px; margin-bottom: 20px; padding: 15px 25px; } body#layout .section h4 { font-size: 20px; letter-spacing: .5px; margin: 0 0 15px; text-transform: capitalize; } body#layout .widget-content { border-radius: 7px; margin-bottom: 5px; } body#layout .editlink.icon { z-index: 99; } body#layout .s { position: static; } body#layout #license { background-color: #caffe4; } body#layout header:before { content: 'IGNIPLEX v3.1'; border: 1px solid #009688; border-radius: 100px; font: normal 400 24px Arial, sans-serif; left: 30px; padding: 12px 16px; top: 25px; } body#layout header:after { content: 'Premium Blogger theme by igniel.com - DEMO: igniplex.blogspot.com'; color: #666; font: normal 400 14px Arial, sans-serif; right: 30px; top: 45px; } body#layout header:before, body#layout header:after { color: #009688; position: absolute; } body#layout #header { margin-right: 15px; width: 42%; } body#layout #settings { background-color: #cae8ff; border: 1px solid #aadddd; width: 44%; } body#layout #HTML3, body#layout #HTML30 { margin-right: 15px; width: 48%; } body#layout #HTML4 { width: 50%; } body#layout .menu { margin-left: 0; } body#layout .menu h4 { width: 100%; } body#layout .igniplex { width: 100%; } body#layout main { margin-right: 15px; } body#layout main { width: 62%; } body#layout aside { display: inline-block; width: 36%; } body#layout aside .section:first-of-type { margin-bottom: 0; } body#layout #HTML1 .widget-content { background-color: #009688; color: #fdfdfd; text-decoration: underline; } body#layout #license #HTML1 .widget-content .layout-title:after { content: '(Masukkan lisensi di sini)'; display: inline-block; font-size: 13px; margin-left: 10px; } body#layout #HTML2 .widget-content { background-color: #03a9f4; color: #fdfdfd; } body#layout #HTML2 .layout-title { margin-left: 0; } body#layout #HTML2 .widget-content .layout-title:after { content: 'Edit theme feature'; display: block; font-size: 13px; white-space: nowrap; text-decoration: underline; } body#layout #HTML1 .widget-content .editlink.icon, body#layout #HTML2 .widget-content .editlink.icon { background-color: #fdfdfd; background-size: 20px 20px; border-radius: 100px; padding: 3px; } body#layout .middle { border: 1px solid #ccc; border-radius: 7px; padding: 1.25rem 1rem; } body#layout #sticky { margin-top: 20px; } body#layout .footer { margin-top: 20px; } body#layout #footer1, body#layout #footer2, body#layout #footer3 { width: 27%; } body#layout #footer1, body#layout #footer2 { margin-right: 13px; } body#layout .credit { display: block; }
